import React from "react";

export default function OrderItem({ order, onEdit, onDelete }) {
    return (
        <div className="userRow">
            <div className="userMain">
                <div className="userHeader">
                    <div className="userId">#{order.id} • Дата: {order.date.slice(0, 10)}</div>
                    <div className="userName">Итого: {order.total} ₽</div>
                </div>
                <div className="userDesc">
                    Товары: {order.items.map(item => item.product ? `${item.product.name} x${item.quantity}` : 'Неизвестный продукт').join(', ')}
                </div>
            </div>
            <div className="userActions">
                <button className="btn" onClick={() => onEdit(order)}>Редактировать</button>
                <button className="btn btn--danger" onClick={() => onDelete(order.id)}>Удалить</button>
            </div>
        </div>
    );
}
